import { useLocation, Link } from "react-router-dom";
import { useEffect } from "react";
import notFoundImage from "@/assets/404-illustration.jpg";

const NotFound = () => {
  const location = useLocation();

  useEffect(() => {
    console.error("404 Error: User attempted to access non-existent route:", location.pathname);
  }, [location.pathname]);

  return (
    <div className="flex min-h-screen items-center justify-center bg-muted">
      <div className="text-center max-w-md px-6">
        <img 
          src={notFoundImage} 
          alt="404 Page Not Found - Construction worker looking confused at empty blueprint" 
          className="w-64 h-64 mx-auto mb-6"
        />
        <h1 className="mb-4 text-5xl font-bold text-primary-dark">404</h1>
        <p className="mb-6 text-xl text-muted-foreground">Oops! This page is under construction.</p>
        <Link 
          to="/" 
          className="inline-block bg-primary text-white px-6 py-3 rounded-full font-semibold hover:bg-primary/90 transition-colors"
        >
          Return to Home
        </Link>
      </div>
    </div>
  );
};

export default NotFound;
